code.C:
#include <stdio.h>
#include <stdbool.h>
#define MAX_N 500
#define MAX_S 100000

int weights[MAX_N];
bool marked[MAX_S + 1];

void dfs(int v, int sum, int* edges, int* next, int* head, int n) {
    sum += weights[v];
    marked[sum] = true;
    for (int i = head[v]; i != -1; i = next[i]) {
        dfs(edges[i], sum, edges, next, head, n);
    }
}

int main() {
    int n;
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        scanf("%d", &weights[i]);
    }
    int* edges = (int*) malloc((n - 1) * sizeof(int));
    int* next = (int*) malloc((n - 1) * sizeof(int));
    int* head = (int*) malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        head[i] = -1;
    }
    for (int i = 1; i < n; i++) {
        int parent;
        scanf("%d", &parent);
        parent--;
        edges[i - 1] = i;
        next[i - 1] = head[parent];
        head[parent] = i - 1;
    }
    dfs(0, 0, edges, next, head, n);
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += weights[i];
    }
    for (int i = 1; i <= sum; i++) {
        printf("%c", marked[i] ? '1' : '0');
    }
    printf("\n");
    return 0;
}

