code.Java:
import java.util.Scanner;
public class Main {
    static final int MAX_N = 500;
    static final int MAX_S = 100000;
    public static void dfs(int v, int sum, int[] edges, int[] next, int[] head, int[] weights, boolean[] marked) {
        sum += weights[v];
        marked[sum] = true;
        for (int i = head[v]; i != -1; i = next[i]) {
            dfs(edges[i], sum, edges, next, head, weights, marked);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] weights = new int[n];
        for (int i = 0; i < n; i++) {
            weights[i] = scanner.nextInt();
        }
        int[] edges = new int[n - 1];
        int[] next = new int[n - 1];
        int[] head = new int[n];
        for (int i = 0; i < n; i++) {
            head[i] = -1;
        }
        for (int i = 1; i < n; i++) {
            int parent = scanner.nextInt() - 1;
            edges[i - 1] = i;
            next[i - 1] = head[parent];
            head[parent] = i - 1;
        }
        boolean[] marked = new boolean[MAX_S + 1];
        dfs(0, 0, edges, next, head, weights, marked);
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += weights[i];
        }
        for (int i = 1; i <= sum; i++) {
            System.out.print(marked[i] ? '1' : '0');
        }
        System.out.println();
    }
}

