const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function dfs(v, sum, edges, next, head, weights, marked) {
    sum += weights[v];
    marked[sum] = true;
    let i = head[v];
    while (i != -1) {
        dfs(edges[i], sum, edges, next, head, weights, marked);
        i = next[i];
    }
}
let n = parseInt(input[idx++]);
let weights = input[idx++].split(' ').map(x => parseInt(x));
let edges = new Array(n - 1);
let next = new Array(n - 1);
let head = new Array(n).fill(-1);
for (let i = 1; i < n; i++) {
    let parent = parseInt(input[idx++]) - 1;
    edges[i - 1] = i;
    next[i - 1] = head[parent];
    head[parent] = i - 1;
}
let marked = new Array(100000 + 1).fill(false);
dfs(0, 0, edges, next, head, weights, marked);
let sum = weights.reduce((a, b) => a + b, 0);
let result = '';
for (let i = 1; i <= sum; i++) {
    result += marked[i] ? '1' : '0';
}
console.log(result);

